package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvPensioenZorgSector;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.SupWrkwBv;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;

@Slf4j
public class BerekenBvExceptioneel extends AbstractBerekenBv {

    public static final int PRECISIE = 2;

    public BerekenBvExceptioneel(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        initFiscaleConstanten(rekenTijd);
        LoonElementManager manager = mainContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            if (BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                berekenBvExceptioneel(mainContext, manager, opdracht);
            }
        }
        BvPensioenZorgSector bvPensioenZorgSector = new BvPensioenZorgSector(RekenBvKey.BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY, taxdatum, constantManager);
        bvPensioenZorgSector.behandel(mainContext);
        return CONTINUE_PROCESSING;
    }


    private void berekenBvExceptioneel(RekenContext mainContext, LoonElementManager manager, Opdracht opdracht) {
        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
        if (!opdrachtContext.getBoolean(RekenChainKey.SCHOOLVERLATER_KEY)) {
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
            Money belastbaarExceptioneel = getBelastbaar(RekenBvKey.BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY, RekenBbKey.BELASTBAAR_KEY, loonElementen);
            Money jaarInkomen = opdrachtContext.getMoney(RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_KEY);
            Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
            Money bedrijfsvoorheffingExceptioneel =
                    berekenBVExceptioneel(opperLaatsteGegevens, jaarInkomen, belastbaarExceptioneel, false, opdrachtContext);
            herverdeelBedrijfsvoorheffing(RekenBvKey.BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY, bedrijfsvoorheffingExceptioneel, RekenBbKey.BELASTBAAR_KEY,
                    belastbaarExceptioneel, loonElementen);
        }
    }

    protected Money berekenBVExceptioneel(Opper opper, Money jaarBedrag, Money belastbaar, boolean vakantieGeld, RekenContext opdrachtContext) {
        log.debug("BerekenBvExceptioneel.berekenBVExceptioneel(opper: {}, jaarBedrag: {}, belastbaar: {}, vakantieGeld: {})", opper, jaarBedrag, belastbaar,
                vakantieGeld);
        SupWrkwBv fiscaleWerkwijze = opper.getOpdrachtFiscaliteit().getWerkwijzeSupplement();
        log.debug("fiscaleWerkwijze:{}", fiscaleWerkwijze);

        RekenTijd rekenTijd = opdrachtContext.getRekenTijd();
        Money bedrijfsvoorheffing = Money.ZERO;
        RkmTijdperk tijdperk = RkmTijdperk.getTijdperk(rekenTijd);
        if (belastbaar.signum() > 0) {
            switch (fiscaleWerkwijze) {
                case BAREMA_GN_KUMUL:
                    bedrijfsvoorheffing = berekenBVExceptioneelBaremaGeenCumul(opper, tijdperk, jaarBedrag, belastbaar, vakantieGeld);
                    break;
                case PERCENTAGE:
                    bedrijfsvoorheffing = berekenBVExceptioneelPercenetage(opper, belastbaar);
                    break;
                case BEDRAG:
                    bedrijfsvoorheffing = opper.getOpdrachtFiscaliteit().getBedragSupplement();
                    break;
                case BAREMA_INV_PVH:
                    bedrijfsvoorheffing = berekenBVExceptioneelInversePvh(opper, tijdperk, jaarBedrag, belastbaar, vakantieGeld, opdrachtContext);
                    break;
                default:
                    RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
                    regulManager.doRegulException(opper.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
                    break;
            }
        }
        log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);
        return bedrijfsvoorheffing;
    }

    private Money berekenBVExceptioneelBaremaGeenCumul(Opper opper, RkmTijdperk tijdperk, Money jaarBedrag, Money belastbaar, boolean vakantieGeld) {
        boolean isJobStudent = WerknemersKengetalFactory.isStudent(opper, tijdperk);
        log.debug("isJobStudent:{}", isJobStudent);
        if (isJobStudent) {
            return Money.ZERO;
        } else {
            return berekenBVExceptioneelBarema(opper.getOpdracht().getPersoon(), jaarBedrag, belastbaar, vakantieGeld);
        }
    }

    private Money berekenBVExceptioneelPercenetage(Opper opper, Money belastbaar) {
        BigDecimal bvPercentageSupplement = opper.getOpdrachtFiscaliteit().getPercentageSupplement().movePointLeft(PRECISIE);
        log.debug("bvPercentageSupplement:{}", bvPercentageSupplement);
        return belastbaar.multiply(bvPercentageSupplement).round(PRECISIE);
    }

    private Money berekenBVExceptioneelInversePvh(
            Opper opper, RkmTijdperk tijdperk, Money jaarBedrag, Money belastbaar, boolean vakantieGeld, RekenContext opdrachtContext) {
        boolean isJobStudent = WerknemersKengetalFactory.isStudent(opper, tijdperk);
        log.debug("isJobStudent:{}", isJobStudent);
        if (isJobStudent) {
            return Money.ZERO;
        } else {
            BigDecimal prestatieVerhouding = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIEVERHOUDING_KEY, opper);
            if (prestatieVerhouding.signum() == 0) {
                prestatieVerhouding = BigDecimal.ONE;
                RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
                regulManager.doRegulException(opper.getOpdracht(), Regulkode.BASISBETAALBREUK_NUL);
            }
            log.debug("prestatieVerhouding:{}", prestatieVerhouding);
            Money jaarBedragInvPvh = jaarBedrag.divide(prestatieVerhouding);
            log.debug("jaarBedragInvPvh:{}", prestatieVerhouding);
            return berekenBVExceptioneelBarema(opper.getOpdracht().getPersoon(), jaarBedragInvPvh, belastbaar, vakantieGeld);
        }
    }

    private static final int AANTAL_GRENZEN_BAREMA = 13;

    private Money berekenBVExceptioneelBarema(Persoon persoon, Money jaarInkomen, Money belastbaar, boolean vakantiegeld) {
        log.debug("BerekenBvExceptioneel.berekenBVExceptioneelBarema(persoon: {}, jaarInkomen: {}, belastbaar: {}, vakantieGeld: {})", persoon, jaarInkomen, belastbaar,
                vakantiegeld);
        int grensNr = 1;
        while (grensNr < AANTAL_GRENZEN_BAREMA && jaarInkomen.compareTo(fiscaleConstanten.getGrensBVExceptioneelVakantieGeld(grensNr)) > 0) {
            grensNr++;
        }
        log.debug("grensNr:{}", grensNr);
        BigDecimal percentageBV =
                vakantiegeld ? fiscaleConstanten.getPercentageBVVakantieGeld(grensNr) : fiscaleConstanten.getPercentageBVExceptioneel(grensNr);
        log.debug("percentageBV:{}", percentageBV);

        PersoonsFiscaliteit persoonsFiscaliteit = RekenTools.getPersoonsFiscaliteitLaatsteGegevens(persoon);
        int kinderenTenLaste = persoonsFiscaliteit.getTotaalAantalKinderenTenLaste();
        int waarvanInvalide = persoonsFiscaliteit.getAantalMinderValideKinderenTenLaste();

        log.debug("kinderenTenLaste:{} waarvanInvalide:{}", kinderenTenLaste, waarvanInvalide);

        Money grensVrijstelling = fiscaleConstanten.getGrensVrijstellingKinderenTenLasteBVExceptioneel(kinderenTenLaste + waarvanInvalide);
        Money grensVermindering = fiscaleConstanten.getGrensVerminderingKinderenTenLasteBVExceptioneel(kinderenTenLaste + waarvanInvalide);
        BigDecimal percentageVermindering =
                fiscaleConstanten.getPercentageVrijstellingKinderenTenLasteBVExceptioneel(kinderenTenLaste + waarvanInvalide);
        log.debug("grensVrijstelling:{}", grensVrijstelling);
        log.debug("grensVermindering:{}", grensVermindering);
        log.debug("percentageVermindering:{}", percentageVermindering);

        if (jaarInkomen.compareTo(grensVrijstelling) < 0) {
            belastbaar = belastbaar.subtract(grensVrijstelling.subtract(jaarInkomen));
            log.debug("jaarInkomen<grensVrijstelling: belastbaar=belastbaar - (grensVrijstelling-jaarInkomen):{}", belastbaar);
        }
        belastbaar = belastbaar.max(Money.ZERO);
        log.debug("belastbaar:{}", belastbaar);
        if (grensVermindering.signum() > 0 && jaarInkomen.compareTo(grensVermindering) <= 0) {
            percentageBV = percentageBV.multiply(BigDecimal.ONE.subtract(percentageVermindering.movePointLeft(PRECISIE)));
            log.debug("grensVermindering>0 && jaarInkomen<=grensVermindering:percentageBV= percentageBV*(1-percentageVermindering){}", percentageBV);
        }
        Money bedrijfsVoorheffing = belastbaar.multiply(percentageBV.movePointLeft(PRECISIE));
        bedrijfsVoorheffing = bedrijfsVoorheffing.max(Money.ZERO);
        bedrijfsVoorheffing = bedrijfsVoorheffing.round(PRECISIE);
        return bedrijfsVoorheffing;
    }

}
